<section class="container section"><h1>Reportes</h1><form class="panel filter-form" method="get" action="index.php"><input type="hidden" name="route" value="admin/reports"><div class="form-grid"><label>Desde<input type="date" name="from" value="<?=Security::e($reports['from'])?>"></label><label>Hasta<input type="date" name="to" value="<?=Security::e($reports['to'])?>"></label></div><button class="btn">Filtrar reservaciones por fecha</button> <a class="btn secondary" href="index.php?route=admin/reports">Limpiar</a></form><div class="report-grid"><div class="panel"><h2>Reservaciones por destino</h2><?php foreach($reports['destinations'] as $r):?><div class="bar-row"><span><?=Security::e($r['name'])?></span><b><?=$r['total']?></b></div><?php endforeach;?></div><div class="panel"><h2>Hoteles más reservados</h2><?php foreach($reports['hotels'] as $r):?><div class="bar-row"><span><?=Security::e($r['name'])?></span><b><?=$r['total']?></b></div><?php endforeach;?></div><div class="panel"><h2>Actividades más solicitadas</h2><?php foreach($reports['activities'] as $r):?><div class="bar-row"><span><?=Security::e($r['name'])?></span><b><?=$r['total']?></b></div><?php endforeach;?></div></div><div class="panel"><h2>Reservaciones e ingresos por fecha</h2><div class="table-wrap"><table><thead><tr><th>Fecha</th><th>Reservaciones</th><th>Ingresos estimados</th></tr></thead><tbody><?php foreach($reports['dates'] as $r):?><tr><td><?=$r['fecha']?></td><td><?=$r['total']?></td><td>₡<?=number_format($r['ingresos'],2)?></td></tr><?php endforeach;?><?php if(!$reports['dates']):?><tr><td colspan="3">No hay información en ese rango.</td></tr><?php endif;?></tbody></table></div></div><div class="panel"><h2>Usuarios registrados</h2><div class="table-wrap"><table><thead><tr><th>Nombre</th><th>Correo</th><th>Rol</th><th>Estado</th><th>Registro</th></tr></thead><tbody><?php foreach($reports['users'] as $u):?><tr><td><?=Security::e($u['name'])?></td><td><?=Security::e($u['email'])?></td><td><?=Security::e($u['role'])?></td><td><?=$u['status']?'Activo':'Inactivo'?></td><td><?=$u['created_at']?></td></tr><?php endforeach;?></tbody></table></div></div></section>
